import os, sys
import datetime as dt

archive_format = {
  'tgz': 'tar', 'gz': 'gzip',
  'zip': None, '7z' : '7z'
}


def make_archives(sourcepath, filetype):

  sourcePath = sourcepath.strip()
  destPath = os.getenv("HOME") + '/Archive'
  archive = archive_format[filetype]

  now = dt.datetime.now().strftime('%Y%m%d%H%M')

  archive_file = '{}-{}'.format(sourcePath, now)
  sourceFile = '{}/{}'.format(destPath, sourcepath)


  for (dirname, _, filenames) in os.walk(sourcepath):

    for file in filenames:

      filename =  os.path.join(dirname, file)
      arch = archive_file +'/'+ filename


      print('{} {} {}'.format(archive, sourceFile, arch))

      cmd = '{} {} {}'.format(
        'tar', 'cC', '--ignore-failed-read')

      os.system('{} -cf {} -C {} {}'.format(cmd, arch, sourceFile, file))

  return 0

